enum VehicleType { CAR, TRUCK, MOTORCYCLE }
enum VehicleSize { SMALL, MEDIUM, LARGE }

interface Vehicle {
    VehicleSize getSize();
    double getHourlyRate();
    String getType();
}

class Car implements Vehicle {
    public VehicleSize getSize() { return VehicleSize.MEDIUM; }
    public double getHourlyRate() { return 20.0; }
    public String getType() { return "Car"; }
}

class Truck implements Vehicle {
    public VehicleSize getSize() { return VehicleSize.LARGE; }
    public double getHourlyRate() { return 50.0; }
    public String getType() { return "Truck"; }
}

class Motorcycle implements Vehicle {
    public VehicleSize getSize() { return VehicleSize.SMALL; }
    public double getHourlyRate() { return 10.0; }
    public String getType() { return "Motorcycle"; }
}

class VehicleFactory {
    public static Vehicle create(VehicleType type) {
        return switch (type) {
            case CAR        -> new Car();
            case TRUCK      -> new Truck();
            case MOTORCYCLE -> new Motorcycle();
        };
    }
}

public class Main {
    public static void main(String[] args) {
        Vehicle v1 = VehicleFactory.create(VehicleType.CAR);
        System.out.println(v1.getType() + " | Size: " + v1.getSize() + " | Rate: $" + v1.getHourlyRate() + "/hr");

        Vehicle v2 = VehicleFactory.create(VehicleType.TRUCK);
        System.out.println(v2.getType() + " | Size: " + v2.getSize() + " | Rate: $" + v2.getHourlyRate() + "/hr");

        Vehicle v3 = VehicleFactory.create(VehicleType.MOTORCYCLE);
        System.out.println(v3.getType() + " | Size: " + v3.getSize() + " | Rate: $" + v3.getHourlyRate() + "/hr");
    }
