#include <iostream>
#include <memory>
#include <string>
using namespace std;

enum class VehicleSize { SMALL, MEDIUM, LARGE };
enum class VehicleType { CAR, TRUCK, MOTORCYCLE };

class Vehicle {
public:
    virtual ~Vehicle() = default;
    virtual VehicleSize getSize() const = 0;
    virtual double getHourlyRate() const = 0;
    virtual string getType() const = 0;
};

class Car : public Vehicle {
public:
    VehicleSize getSize() const override { return VehicleSize::MEDIUM; }
    double getHourlyRate() const override { return 20.0; }
    string getType() const override { return "Car"; }
};

class Truck : public Vehicle {
public:
    VehicleSize getSize() const override { return VehicleSize::LARGE; }
    double getHourlyRate() const override { return 50.0; }
    string getType() const override { return "Truck"; }
};

class Motorcycle : public Vehicle {
public:
    VehicleSize getSize() const override { return VehicleSize::SMALL; }
    double getHourlyRate() const override { return 10.0; }
    string getType() const override { return "Motorcycle"; }
};

class VehicleFactory {
public:
    static unique_ptr<Vehicle> create(VehicleType type) {
        switch (type) {
            case VehicleType::CAR:        return make_unique<Car>();
            case VehicleType::TRUCK:      return make_unique<Truck>();
            case VehicleType::MOTORCYCLE: return make_unique<Motorcycle>();
            default: throw invalid_argument("Unknown vehicle type");
        }
    }
};

int main() {
    auto v1 = VehicleFactory::create(VehicleType::CAR);
    cout << v1->getType() << " | Rate: $" << v1->getHourlyRate() << "/hr" << endl;

    auto v2 = VehicleFactory::create(VehicleType::TRUCK);
    cout << v2->getType() << " | Rate: $" << v2->getHourlyRate() << "/hr" << endl;

    auto v3 = VehicleFactory::create(VehicleType::MOTORCYCLE);
    cout << v3->getType() << " | Rate: $" << v3->getHourlyRate() << "/hr" << endl;

    return 0;
}

