#include <iostream>
#include <string>
#include <memory>
#include <unordered_map>
#include <functional>
#include <stdexcept>
using namespace std;

class Notification {
public:
    virtual ~Notification() = default;
    virtual void send(const string& message) = 0;
    virtual string getChannel() const = 0;
};

class EmailNotification : public Notification {
public:
    void send(const string& msg) override { cout << "[EMAIL] " << msg << endl; }
    string getChannel() const override { return "EMAIL"; }
};

class SMSNotification : public Notification {
public:
    void send(const string& msg) override { cout << "[SMS] " << msg << endl; }
    string getChannel() const override { return "SMS"; }
};

class TelegramNotification : public Notification {
public:
    void send(const string& msg) override { cout << "[TELEGRAM] " << msg << endl; }
    string getChannel() const override { return "TELEGRAM"; }
};

class NotificationRegistry {
    using Creator = function<unique_ptr<Notification>()>;
    unordered_map<string, Creator> registry;
public:
    NotificationRegistry() {
        registry["EMAIL"] = []() { return make_unique<EmailNotification>(); };
        registry["SMS"]   = []() { return make_unique<SMSNotification>(); };
    }

    void registerType(const string& key, Creator creator) {
        registry[key] = move(creator);
    }

    unique_ptr<Notification> create(const string& key) {
        auto it = registry.find(key);
        if (it == registry.end()) throw invalid_argument("Unknown: " + key);
        return it->second();
    }
};

int main() {
    NotificationRegistry registry;
    registry.create("EMAIL")->send("Order confirmed!");
    registry.create("SMS")->send("OTP: 1234");

    // Dynamic registration
    registry.registerType("TELEGRAM", []() {
        return make_unique<TelegramNotification>();
    });
    registry.create("TELEGRAM")->send("Welcome!");

    return 0;
}

